CREATE TABLE IF NOT EXISTS comite_agentes (
  id TEXT PRIMARY KEY,
  categoria TEXT NOT NULL,
  nome TEXT NOT NULL,
  descricao_curta TEXT NOT NULL,
  system_prompt TEXT NOT NULL,
  icone TEXT NOT NULL,
  is_active INTEGER DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS comite_casos_salvos (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  agent_id TEXT NOT NULL,
  title TEXT NOT NULL,
  history_json TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (agent_id) REFERENCES comite_agentes(id)
);

CREATE INDEX IF NOT EXISTS idx_comite_casos_user ON comite_casos_salvos(user_id);
CREATE INDEX IF NOT EXISTS idx_comite_casos_agent ON comite_casos_salvos(agent_id);

CREATE TABLE IF NOT EXISTS comite_xp_usuario (
  user_id TEXT PRIMARY KEY,
  xp_total INTEGER DEFAULT 0,
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS comite_caso_semana (
  id TEXT PRIMARY KEY,
  titulo TEXT NOT NULL,
  descricao_curta TEXT NOT NULL,
  agente_id TEXT NOT NULL,
  initial_message TEXT NOT NULL,
  is_active INTEGER DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (agente_id) REFERENCES comite_agentes(id)
);

